<script setup lang="ts">import type { DataSourceReference } from '@/api/types';defineProps<{sources:DataSourceReference[]}>();const format=(value?:string)=>value?new Intl.DateTimeFormat('zh-CN',{dateStyle:'medium',timeStyle:'short'}).format(new Date(value)):'供应商未提供';const badge=(source:DataSourceReference)=>source.provider==='DEMO_STUB'?'演示数据':source.freshness==='FRESH'?'实时':source.freshness==='STALE'?'缓存数据':'不可用'</script>
<template><div v-if="sources.length" class="sources"><strong>数据来源</strong><ul><li v-for="source in sources" :key="`${source.provider}-${source.retrievedAt}`"><a :href="source.sourceUrl" target="_blank" rel="noopener noreferrer">{{source.label}}</a><span>获取于 {{format(source.retrievedAt)}}</span><span v-if="source.sourceUpdatedAt"> · 源更新于 {{format(source.sourceUpdatedAt)}}</span><span class="freshness" :class="source.freshness.toLowerCase()">{{badge(source)}}</span></li></ul></div></template>
